import{c as e,Q as a,j as n,m as o}from"./chunks/framework.DpF7k2f3.js";const u=JSON.parse('{"title":"Chapter 9: LangChain in Action","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"en/part3-practice/chapter9.md","filePath":"en/part3-practice/chapter9.md"}'),i={name:"en/part3-practice/chapter9.md"};function r(s,t,l,p,h,c){return a(),n("div",null,[...t[0]||(t[0]=[o('<h1 id="chapter-9-langchain-in-action" tabindex="-1">Chapter 9: LangChain in Action <a class="header-anchor" href="#chapter-9-langchain-in-action" aria-label="Permalink to &quot;Chapter 9: LangChain in Action&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><p>Brothers and sisters, it&#39;s time for another hands-on session!</p><p>In previous chapters, we built solid foundations—you can call LLMs (Chapter 5), know how to connect AI to knowledge bases (Chapter 6), and understand how Agents work (Chapter 7). Now it&#39;s time to <strong>connect these capabilities into something truly usable</strong>.</p><p>In this chapter, we&#39;ll tackle LangChain—the most popular AI application development framework.</p><p>Let me be honest: <strong>LangChain is easy to get started with, hard to master.</strong> Official tutorials are all Hello World level. When you actually go to production, various problems arise: version incompatibilities, debugging difficulties, performance issues...</p><p>But! LangChain is still the most mainstream AI application development framework. Learning it adds points to job hunting and doubles efficiency on projects. And in 2025-2026, LangChain launched <strong>LangGraph</strong>, which directly turns complex Agent orchestration into declarative programming—like evolving from assembly to Python.</p><p>So in this chapter, I&#39;ll take you through:</p><ul><li>LangChain architecture and core modules (no废话)</li><li>LCEL in depth—this is LangChain&#39;s essence</li><li><strong>Main attraction: LangGraph</strong>—2026&#39;s standard Agent development tool</li><li>RAG implementation upgraded from toy to production grade</li><li>Deep dive into multi-tool Agents</li></ul><hr><blockquote><p><strong>Full translation coming soon. You can read the Chinese version in the meantime.</strong></p><p>中文原文：<a href="/jumpstart-ai/zh/part3-practice/chapter9.html">阅读中文版</a></p></blockquote>',11)])])}const g=e(i,[["render",r]]);export{u as __pageData,g as default};
